import React, { useId } from 'react';
import { getTextareaIds, getTextareaAriaProps } from '../lib/core';
import type { TextareaBaseProps } from '../lib/core';
import styles from './textarea.module.scss';

export interface TextareaProps extends React.TextareaHTMLAttributes<HTMLTextAreaElement>, TextareaBaseProps {}

const Textarea = React.forwardRef<HTMLTextAreaElement, TextareaProps>(({ className = '', label, error, helperText, required, id: providedId, ...props }, ref) => {
	const generatedId = useId();
	const id = providedId || generatedId;
	const ids = getTextareaIds(id);
	const ariaProps = getTextareaAriaProps(ids, error, helperText);

	return (
		<div className={styles.textareaWrapper}>
			{label && (
				<label htmlFor={id} className={`${styles.label} ${required ? styles.required : ''}`}>
					{label}
				</label>
			)}
			<textarea ref={ref} id={id} className={`${styles.textarea} ${error ? styles.error : ''} ${className}`} {...ariaProps} {...props} />
			{error && (
				<span id={ids.error} className={styles.errorText}>
					{error}
				</span>
			)}
			{!error && helperText && (
				<span id={ids.helper} className={styles.helperText}>
					{helperText}
				</span>
			)}
		</div>
	);
});

Textarea.displayName = 'Textarea';

export { Textarea };
export default Textarea;

@use 'sass:color';
@use '../../../styles/variables/colors' as *;

.textareaWrapper {
	display: flex;
	flex-direction: column;
	gap: $spacing-1;
	width: 100%;
}

.textarea {
	display: flex;
	min-height: 5rem;
	width: 100%;
	border-radius: $radius;
	border: 1px solid $border;
	background-color: $background;
	padding: $spacing-3 $spacing-3;
	font-size: $text-sm;
	color: $foreground;
	transition: all $transition-fast;
	outline: none;
	resize: vertical;
	font-family: inherit;
	line-height: $leading-normal;

	&::placeholder {
		color: color.mix(white, $foreground, 60%);
	}

	&:focus {
		outline: none;
		border-color: $ring;
		box-shadow: 0 0 0 1px $ring;
	}

	&:disabled,
	&.disabled {
		pointer-events: none;
		opacity: 0.5;
		cursor: not-allowed;
		background-color: color.mix(white, $background, 50%);
	}

	&.error {
		border-color: $destructive;

		&:focus {
			border-color: $destructive;
			box-shadow: 0 0 0 1px $destructive;
		}
	}
}

.label {
	display: block;
	font-size: $text-sm;
	font-weight: $font-medium;
	color: $foreground;
	line-height: $leading-normal;

	&.required::after {
		content: ' *';
		color: $destructive;
	}
}

.helperText {
	font-size: $text-xs;
	color: color.mix(white, $foreground, 60%);
	line-height: $leading-normal;
}

.errorText {
	font-size: $text-xs;
	color: $destructive;
	line-height: $leading-normal;
}
